import 'dart:async';
import 'dart:convert';

import '../lib/chunk_text_decoder.dart';
import '../lib/event_parser.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

bool sameList(List<String> actual, List<String> expected) {
  if (actual.length != expected.length) return false;
  for (var index = 0; index < actual.length; index++) {
    if (actual[index] != expected[index]) return false;
  }
  return true;
}

Stream<List<int>> oneByteChunks(List<int> bytes) {
  return Stream<List<int>>.fromIterable(bytes.map((byte) => [byte]));
}

Future<void> main() async {
  final international = '\u6771\u4eac\u{1F327}';
  final direct = await decodeByteChunks(oneByteChunks(utf8.encode(international))).join();
  check(direct == international, 'direct decoder is byte-boundary invariant');

  final proxy = Stream<List<int>>.fromIterable([
    utf8.encode('data: first\r'),
    utf8.encode('\ndata: second\r\n'),
  ]);
  check(sameList(await parseEventData(proxy).toList(), ['first', 'second']), 'direct parser line contract');

  final payload = 'na\u00efve \u{1F680}';
  final integrated = oneByteChunks(utf8.encode('data: $payload\r\n'));
  check(sameList(await parseEventData(integrated).toList(), [payload]), 'integrated unicode event contract');
}
